/**
 * Renders project cards into a container element.
 * @param {HTMLElement} container  - The grid element to append cards into.
 * @param {Array}       projects   - Array of project objects to render.
 */
function renderProjects(container, projects) {
  container.innerHTML = projects.map((project, i) => `
    <div class="col-lg-4 col-md-6 portfolio-item" data-aos="fade-up" data-aos-delay="${(i % 3) * 100}">
      <div class="portfolio-wrap">
        <img
          src="${project.img}"
          class="img-fluid"
          alt="${project.title}"
          loading="lazy"
          width="400"
          height="300"
        />
        <div class="portfolio-info">
          <h4>${project.title}</h4>
          <p>${project.category}</p>
          <div class="portfolio-links">
            <a
              href="${project.img}"
              data-gallery="portfolioGallery"
              class="portfolio-lightbox"
              title="${project.title}"
            ><i class="bx bxl-github"></i></a>
            <a href="${project.link}" target="_blank"><i class="bx bx-link"></i></a>
          </div>
        </div>
      </div>
    </div>
  `).join('');

  // Re-initialize GLightbox if available (for the project zoom/lightbox effect)
  if (typeof GLightbox !== 'undefined') {
    GLightbox({
      selector: '.portfolio-lightbox'
    });
  }
}

// ── Homepage: render top-3 featured projects ─────────────────────────────────
const projectsHomeGrid = document.getElementById('projects-grid-home');
if (projectsHomeGrid) {
  const featured = PROJECTS.filter(p => p.featured).slice(0, 3);
  renderProjects(projectsHomeGrid, featured);
}

// ── Projects page: render all projects ───────────────────────────────────────
const projectsAllGrid = document.getElementById('projects-grid-all');
if (projectsAllGrid) {
  renderProjects(projectsAllGrid, PROJECTS);
}
